@baude it's an off-by-one, an actual bug caught by my test:
```diff
diff --git a/pkg/adapter/containers.go b/pkg/adapter/containers.go
index 4a167a3e..c491cdfc 100644
--- a/pkg/adapter/containers.go
+++ b/pkg/adapter/containers.go
@@ -1101,7 +1101,7 @@ func (r *LocalRuntime) Port(c *cliconfig.PortValues) ([]*Container, error) {

        if !c.All {
                names := []string{}
-               if len(c.InputArgs) > 1 {
+               if len(c.InputArgs) >= 1 {
                        names = []string{c.InputArgs[0]}
                }
                containers, err = shortcuts.GetContainersByContext(false, c.Latest, names, r.Runtime)
